	/**
	 * Atomically captures every function implementation referenced by a query subtree. Captured calls retain only the
	 * function instance (or its absence), so later registry replacement cannot invalidate optimizer decisions.
	 */
	@SuppressWarnings("unchecked")
	public static <T extends QueryModelNode> T pinFunctions(T node) {
		FunctionRegistry registry = FunctionRegistry.getInstance();
		synchronized (registry) {
			FunctionPinningVisitor visitor = new FunctionPinningVisitor(registry);
			if (node instanceof FunctionCall && !(node instanceof PinnedFunctionCall)) {
				Function function = registry.get(((FunctionCall) node).getURI()).orElse(null);
				if (function == null || !isRepeatable(function)) {
					node.visit(visitor);
					return node;
				}
				PinnedFunctionCall pinned = new PinnedFunctionCall((FunctionCall) node, function);
				if (node.getParentNode() != null) {
					node.replaceWith(pinned);
				}
				pinned.visit(visitor);
				return (T) pinned;
			}
			node.visit(visitor);
			return node;
		}
	}

	/** Returns the implementation pinned for this call, or the current registry entry for an unpinned call. */
	public static Optional<Function> resolveFunction(FunctionCall node) {
		if (node instanceof PinnedFunctionCall) {
			PinnedFunctionCall pinned = (PinnedFunctionCall) node;
			Function function = pinned.function;
			if (function != null) {
				return Optional.of(function);
			}
			Function registered = FunctionRegistry.getInstance().get(node.getURI()).orElse(null);
			if (registered != null && registered.getClass() == pinned.functionClass) {
				pinned.function = registered;
				return Optional.of(registered);
			}
			return Optional.empty();
		}
		return FunctionRegistry.getInstance().get(node.getURI());
	}

